mapper.select:
WITH HOURS AS ( SELECT LPAD(LEVEL - 1, 2, '0') AS HOUR FROM DUAL CONNECT BY LEVEL <= 24 ), STATUS_STATS AS ( SELECT TO_CHAR(c.CART_STATUSDATE, 'HH24') AS HOUR, COUNT(*) AS STATUS_COUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND c.CART_STATUSDATE IS NOT NULL
AND c.F_DSTATUS = #{f_dstatus}
AND c.F_DSTATUS = #{F_DSTATUS}
AND c.F_DSTATUS = 5
GROUP BY TO_CHAR(c.CART_STATUSDATE, 'HH24') ) SELECT h.HOUR AS "hour", NVL(s.STATUS_COUNT, 0) AS "statusCount" FROM HOURS h LEFT JOIN STATUS_STATS s ON h.HOUR = s.HOUR ORDER BY h.HOUR

WITH PAY_TO_CONFIRM AS ( SELECT COUNT(*) AS TARGET_COUNT, ROUND(AVG(c.CART_STATUSDATE - c.CART_PAYDATE), 2) AS AVG_DAYS, ROUND(AVG((c.CART_STATUSDATE - c.CART_PAYDATE) * 24), 2) AS AVG_HOURS, ROUND(AVG((c.CART_STATUSDATE - c.CART_PAYDATE) * 24 * 60), 2) AS AVG_MINUTES FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND c.F_DSTATUS = 5 AND c.CART_PAYDATE IS NOT NULL AND c.CART_STATUSDATE IS NOT NULL AND c.CART_STATUSDATE >= c.CART_PAYDATE
), CART_TO_PAY AS ( SELECT COUNT(*) AS TARGET_COUNT, ROUND(AVG(c.CART_PAYDATE - c.CART_CREATEDDATE), 2) AS AVG_DAYS, ROUND(AVG((c.CART_PAYDATE - c.CART_CREATEDDATE) * 24), 2) AS AVG_HOURS, ROUND(AVG((c.CART_PAYDATE - c.CART_CREATEDDATE) * 24 * 60), 2) AS AVG_MINUTES FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND c.CART_CREATEDDATE IS NOT NULL AND c.CART_PAYDATE IS NOT NULL AND c.CART_PAYDATE >= c.CART_CREATEDDATE
) SELECT NVL(ptc.TARGET_COUNT, 0) AS "payToConfirmTargetCount", NVL(ptc.AVG_DAYS, 0) AS "avgPayToConfirmDays", NVL(ptc.AVG_HOURS, 0) AS "avgPayToConfirmHours", NVL(ptc.AVG_MINUTES, 0) AS "avgPayToConfirmMinutes", NVL(ctp.TARGET_COUNT, 0) AS "cartToPayTargetCount", NVL(ctp.AVG_DAYS, 0) AS "avgCartToPayDays", NVL(ctp.AVG_HOURS, 0) AS "avgCartToPayHours", NVL(ctp.AVG_MINUTES, 0) AS "avgCartToPayMinutes" FROM PAY_TO_CONFIRM ptc CROSS JOIN CART_TO_PAY ctp

WITH PAID_CART AS ( SELECT c.C_CODE, c.F_CODE, c.PAY_TOTAL, c.USE_POINT, c.SAVE_POINT, c.COUPON_DISCOUNT, NVL(c.PAY_TOTAL, 0) + NVL(c.USE_POINT, 0) + NVL(c.COUPON_DISCOUNT, 0) AS BEFORE_DISCOUNT_AMOUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND NVL(c.F_DSTATUS, 0) != -1
) SELECT COUNT(*) AS "totalPayCount", COUNT(CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 THEN 1 END) AS "couponUseCount", COUNT(CASE WHEN NVL(COUPON_DISCOUNT, 0) = 0 THEN 1 END) AS "couponNotUseCount", CASE WHEN COUNT(*) = 0 THEN 0 ELSE ROUND(COUNT(CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 THEN 1 END) / COUNT(*) * 100, 2) END AS "couponUseRate", NVL(SUM(NVL(COUPON_DISCOUNT, 0)), 0) AS "totalCouponDiscount", NVL(ROUND(AVG(NVL(COUPON_DISCOUNT, 0)), 0), 0) AS "avgCouponDiscountAll", NVL(ROUND(AVG(CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 THEN COUPON_DISCOUNT END), 0), 0) AS "avgCouponDiscountUsed", NVL(MAX(NVL(COUPON_DISCOUNT, 0)), 0) AS "maxCouponDiscount", NVL(SUM(BEFORE_DISCOUNT_AMOUNT), 0) AS "totalBeforeDiscountAmount", CASE WHEN NVL(SUM(BEFORE_DISCOUNT_AMOUNT), 0) = 0 THEN 0 ELSE ROUND(SUM(NVL(COUPON_DISCOUNT, 0)) / SUM(BEFORE_DISCOUNT_AMOUNT) * 100, 2) END AS "couponDiscountRate", COUNT(CASE WHEN NVL(USE_POINT, 0) > 0 THEN 1 END) AS "pointUseCount", COUNT(CASE WHEN NVL(USE_POINT, 0) = 0 THEN 1 END) AS "pointNotUseCount", CASE WHEN COUNT(*) = 0 THEN 0 ELSE ROUND(COUNT(CASE WHEN NVL(USE_POINT, 0) > 0 THEN 1 END) / COUNT(*) * 100, 2) END AS "pointUseRate", NVL(SUM(NVL(USE_POINT, 0)), 0) AS "totalUsePoint", NVL(ROUND(AVG(NVL(USE_POINT, 0)), 0), 0) AS "avgUsePointAll", NVL(ROUND(AVG(CASE WHEN NVL(USE_POINT, 0) > 0 THEN USE_POINT END), 0), 0) AS "avgUsePointUsed", NVL(MAX(NVL(USE_POINT, 0)), 0) AS "maxUsePoint", NVL(SUM(NVL(SAVE_POINT, 0)), 0) AS "totalSavePoint", NVL(ROUND(AVG(NVL(SAVE_POINT, 0)), 0), 0) AS "avgSavePoint", CASE WHEN NVL(SUM(NVL(PAY_TOTAL, 0)), 0) = 0 THEN 0 ELSE ROUND(SUM(NVL(SAVE_POINT, 0)) / SUM(NVL(PAY_TOTAL, 0)) * 100, 2) END AS "savePointRate" FROM PAID_CART

WITH PAID_CART AS ( SELECT c.C_CODE, c.PAY_TOTAL, c.USE_POINT, c.COUPON_DISCOUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND NVL(c.F_DSTATUS, 0) != -1
), USE_TYPE_BASE AS ( SELECT CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 'couponPoint' WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 'couponOnly' WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 'pointOnly' ELSE 'none' END AS USE_TYPE, CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 1 WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 2 WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 3 ELSE 4 END AS SORT_NO, PAY_TOTAL, USE_POINT, COUPON_DISCOUNT FROM PAID_CART ) SELECT USE_TYPE AS "useType", COUNT(*) AS "orderCount", CASE WHEN SUM(COUNT(*)) OVER () = 0 THEN 0 ELSE ROUND(COUNT(*) / SUM(COUNT(*)) OVER () * 100, 2) END AS "orderRate", NVL(SUM(NVL(PAY_TOTAL, 0)), 0) AS "totalPayAmount", NVL(SUM(NVL(COUPON_DISCOUNT, 0)), 0) AS "totalCouponDiscount", NVL(SUM(NVL(USE_POINT, 0)), 0) AS "totalUsePoint", NVL(ROUND(AVG(NVL(PAY_TOTAL, 0)), 0), 0) AS "avgPayAmount" FROM USE_TYPE_BASE GROUP BY USE_TYPE, SORT_NO ORDER BY SORT_NO

WITH PAID_CART AS ( SELECT c.C_CODE, c.PAY_TOTAL, c.USE_POINT, c.COUPON_DISCOUNT, NVL(c.PAY_TOTAL, 0) + NVL(c.USE_POINT, 0) + NVL(c.COUPON_DISCOUNT, 0) AS BEFORE_DISCOUNT_AMOUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND NVL(c.F_DSTATUS, 0) != -1
), COMPARE_BASE AS ( SELECT CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 'couponPoint' WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 'couponOnly' WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 'pointOnly' ELSE 'none' END AS USE_TYPE, CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 1 WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 2 WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 3 ELSE 4 END AS SORT_NO, PAY_TOTAL, USE_POINT, COUPON_DISCOUNT, BEFORE_DISCOUNT_AMOUNT FROM PAID_CART ) SELECT USE_TYPE AS "useType", COUNT(*) AS "orderCount", NVL(SUM(NVL(PAY_TOTAL, 0)), 0) AS "totalPayAmount", NVL(ROUND(AVG(NVL(PAY_TOTAL, 0)), 0), 0) AS "avgPayAmount", NVL(SUM(NVL(BEFORE_DISCOUNT_AMOUNT, 0)), 0) AS "totalBeforeDiscountAmount", NVL(ROUND(AVG(NVL(BEFORE_DISCOUNT_AMOUNT, 0)), 0), 0) AS "avgBeforeDiscountAmount", NVL(SUM(NVL(COUPON_DISCOUNT, 0)), 0) AS "totalCouponDiscount", NVL(ROUND(AVG(NVL(COUPON_DISCOUNT, 0)), 0), 0) AS "avgCouponDiscount", NVL(SUM(NVL(USE_POINT, 0)), 0) AS "totalUsePoint", NVL(ROUND(AVG(NVL(USE_POINT, 0)), 0), 0) AS "avgUsePoint", CASE WHEN NVL(SUM(NVL(BEFORE_DISCOUNT_AMOUNT, 0)), 0) = 0 THEN 0 ELSE ROUND((SUM(NVL(COUPON_DISCOUNT, 0)) + SUM(NVL(USE_POINT, 0))) / SUM(NVL(BEFORE_DISCOUNT_AMOUNT, 0)) * 100, 2) END AS "discountAndPointRate" FROM COMPARE_BASE GROUP BY USE_TYPE, SORT_NO ORDER BY SORT_NO

WITH ANSWER_BASE AS ( SELECT CASE WHEN REGEXP_LIKE(JSON_VALUE(b.B_ANSWER, '$.budget' NULL ON ERROR), '^[0-9]+(\.[0-9]+)?$') THEN TO_NUMBER(JSON_VALUE(b.B_ANSWER, '$.budget' NULL ON ERROR)) END AS BUDGET, CASE WHEN REGEXP_LIKE(JSON_VALUE(b.B_ANSWER, '$.areaSize' NULL ON ERROR), '^[0-9]+(\.[0-9]+)?$') THEN TO_NUMBER(JSON_VALUE(b.B_ANSWER, '$.areaSize' NULL ON ERROR)) END AS AREA_SIZE FROM BOOKING b
AND b.B_ANSWER IS NOT NULL AND b.B_ANSWER IS JSON
) SELECT 'budget' AS "answerType", CASE WHEN BUDGET IS NULL THEN 'unknown' WHEN BUDGET < 500 THEN 'under500' WHEN BUDGET < 1000 THEN '500to1000' WHEN BUDGET < 2000 THEN '1000to2000' WHEN BUDGET < 3000 THEN '2000to3000' ELSE 'over3000' END AS "answerGroup", COUNT(*) AS "bookingCount" FROM ANSWER_BASE GROUP BY CASE WHEN BUDGET IS NULL THEN 'unknown' WHEN BUDGET < 500 THEN 'under500' WHEN BUDGET < 1000 THEN '500to1000' WHEN BUDGET < 2000 THEN '1000to2000' WHEN BUDGET < 3000 THEN '2000to3000' ELSE 'over3000' END UNION ALL SELECT 'area' AS "answerType", CASE WHEN AREA_SIZE IS NULL THEN 'unknown' WHEN AREA_SIZE < 10 THEN 'under10' WHEN AREA_SIZE < 20 THEN '10to20' WHEN AREA_SIZE < 30 THEN '20to30' WHEN AREA_SIZE < 40 THEN '30to40' ELSE 'over40' END AS "answerGroup", COUNT(*) AS "bookingCount" FROM ANSWER_BASE GROUP BY CASE WHEN AREA_SIZE IS NULL THEN 'unknown' WHEN AREA_SIZE < 10 THEN 'under10' WHEN AREA_SIZE < 20 THEN '10to20' WHEN AREA_SIZE < 30 THEN '20to30' WHEN AREA_SIZE < 40 THEN '30to40' ELSE 'over40' END ORDER BY "answerType", "bookingCount" DESC

WITH DONE_BOOKING AS ( SELECT b.ID, b.C_ID, b.C_KIND, b.C_NAME, b.B_CREATEDDATE FROM BOOKING b
AND b.B_STATUS = 'done'
), REVIEW_BASE AS ( SELECT r.ID, r.C_ID, r.C_KIND, r.C_NAME, r.B_CREATEDDATE, MIN(r.IR_CREATEDDATE) AS REVIEW_CREATEDDATE FROM I_REVIEW r WHERE r.C_KIND = 'interior'
AND r.C_ID = #{c_id}
AND r.C_NAME = #{c_name}
GROUP BY r.ID, r.C_ID, r.C_KIND, r.C_NAME, r.B_CREATEDDATE ) SELECT COUNT(d.ID) AS "doneBookingCount", COUNT(CASE WHEN r.ID IS NOT NULL THEN 1 END) AS "reviewWrittenCount", COUNT(CASE WHEN r.ID IS NULL THEN 1 END) AS "reviewNotWrittenCount", CASE WHEN COUNT(d.ID) = 0 THEN 0 ELSE ROUND(COUNT(CASE WHEN r.ID IS NOT NULL THEN 1 END) / COUNT(d.ID) * 100, 2) END AS "reviewWriteRate", NVL(ROUND(AVG(r.REVIEW_CREATEDDATE - d.B_CREATEDDATE), 2), 0) AS "avgReviewAfterDays" FROM DONE_BOOKING d LEFT JOIN REVIEW_BASE r ON d.ID = r.ID AND d.C_ID = r.C_ID AND d.C_KIND = r.C_KIND AND d.C_NAME = r.C_NAME AND d.B_CREATEDDATE = r.B_CREATEDDATE

SELECT TO_CHAR(r.IR_CREATEDDATE, 'YYYY-MM') AS "month", COUNT(*) AS "reviewCount" FROM I_REVIEW r WHERE r.C_KIND = 'interior'
AND r.C_ID = #{c_id}
AND r.C_NAME = #{c_name}
GROUP BY TO_CHAR(r.IR_CREATEDDATE, 'YYYY-MM') ORDER BY "month"

WITH COMPANY_LIKE_CODE AS ( SELECT c.C_ID, c.C_NAME, c.C_KIND, c.C_ID || '/' || c.C_NAME || '/' || c.C_KIND AS LIKE_CODE FROM COMPANY c
), LIKE_BASE AS ( SELECT l.LIKE_CODE, COUNT(*) AS LIKE_COUNT FROM "LIKE" l WHERE l.LIKE_TAG = 'interior' GROUP BY l.LIKE_CODE ), BOOKING_BASE AS ( SELECT b.C_ID, b.C_NAME, b.C_KIND, COUNT(*) AS BOOKING_COUNT, COUNT(CASE WHEN b.B_STATUS IN ('confirmed', 'working', 'done') THEN 1 END) AS CONTRACT_COUNT FROM BOOKING b
GROUP BY b.C_ID, b.C_NAME, b.C_KIND ) SELECT c.C_ID AS "cId", c.C_NAME AS "cName", NVL(l.LIKE_COUNT, 0) AS "likeCount", NVL(b.BOOKING_COUNT, 0) AS "bookingCount", NVL(b.CONTRACT_COUNT, 0) AS "contractCount", CASE WHEN NVL(l.LIKE_COUNT, 0) = 0 THEN 0 ELSE ROUND(NVL(b.BOOKING_COUNT, 0) / l.LIKE_COUNT * 100, 2) END AS "likeToBookingRate", CASE WHEN NVL(l.LIKE_COUNT, 0) = 0 THEN 0 ELSE ROUND(NVL(b.CONTRACT_COUNT, 0) / l.LIKE_COUNT * 100, 2) END AS "likeToContractRate" FROM COMPANY_LIKE_CODE c LEFT JOIN LIKE_BASE l ON c.LIKE_CODE = l.LIKE_CODE LEFT JOIN BOOKING_BASE b ON c.C_ID = b.C_ID AND c.C_KIND = b.C_KIND AND c.C_NAME = b.C_NAME ORDER BY "likeCount" DESC, "bookingCount" DESC

WITH COMPANY_BASE AS ( SELECT c.C_ID, c.C_KIND, c.C_NAME, c.C_TEL, c.C_ADDR, c.C_INFO, c.C_BOSS FROM COMPANY c
), INTERIOR_BASE AS ( SELECT i.C_ID, i.C_KIND, i.C_NAME, COUNT(*) AS INTERIOR_INFO_COUNT, COUNT(CASE WHEN i.I_TAG IS NOT NULL AND TRIM(i.I_TAG) IS NOT NULL THEN 1 END) AS TAG_COUNT, COUNT(CASE WHEN i.I_TEXT IS NOT NULL AND TRIM(i.I_TEXT) IS NOT NULL THEN 1 END) AS TEXT_COUNT FROM INTERIOR i WHERE i.C_KIND = 'interior'
AND i.C_ID = #{c_id}
AND i.C_NAME = #{c_name}
GROUP BY i.C_ID, i.C_KIND, i.C_NAME ), IMG_BASE AS ( SELECT img.DIR_A AS C_ID, img.DIR_B AS C_KIND, img.DIR_C AS C_NAME, COUNT(CASE WHEN img.IMG_KIND = 'LOGO' THEN 1 END) AS LOGO_COUNT, COUNT(CASE WHEN img.IMG_KIND = 'C_PROFILE' THEN 1 END) AS PROFILE_IMG_COUNT, COUNT(CASE WHEN img.IMG_KIND = 'I_EXAMPLE' AND (img.IMG_TAG != 'MODEL' OR img.IMG_TAG IS NULL) THEN 1 END) AS EXAMPLE_IMG_COUNT, COUNT(CASE WHEN img.IMG_KIND = 'I_EXAMPLE' AND img.IMG_TAG = 'MODEL' THEN 1 END) AS MODEL_COUNT FROM IMG img WHERE img.DIR_B = 'interior'
AND img.DIR_A = #{c_id}
AND img.DIR_C = #{c_name}
GROUP BY img.DIR_A, img.DIR_B, img.DIR_C ), EXAMPLE_BASE AS ( SELECT e.C_ID, e.C_KIND, e.C_NAME, COUNT(*) AS EXAMPLE_COUNT FROM I_EXAMPLE e
GROUP BY e.C_ID, e.C_KIND, e.C_NAME ) SELECT c.C_ID AS "cId", c.C_NAME AS "cName", CASE WHEN c.C_TEL IS NOT NULL AND TRIM(c.C_TEL) IS NOT NULL THEN 1 ELSE 0 END AS "telFilled", CASE WHEN c.C_ADDR IS NOT NULL AND TRIM(c.C_ADDR) IS NOT NULL THEN 1 ELSE 0 END AS "addrFilled", CASE WHEN c.C_INFO IS NOT NULL AND TRIM(c.C_INFO) IS NOT NULL THEN 1 ELSE 0 END AS "infoFilled", CASE WHEN c.C_BOSS IS NOT NULL AND TRIM(c.C_BOSS) IS NOT NULL THEN 1 ELSE 0 END AS "bossFilled", CASE WHEN NVL(i.TAG_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "interiorTagFilled", CASE WHEN NVL(i.TEXT_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "interiorTextFilled", CASE WHEN NVL(img.LOGO_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "logoFilled", CASE WHEN NVL(img.PROFILE_IMG_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "profileImageFilled", CASE WHEN NVL(e.EXAMPLE_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "exampleFilled", CASE WHEN NVL(img.EXAMPLE_IMG_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "exampleImageFilled", CASE WHEN NVL(img.MODEL_COUNT, 0) > 0 THEN 1 ELSE 0 END AS "modelFilled", ROUND(( CASE WHEN c.C_TEL IS NOT NULL AND TRIM(c.C_TEL) IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN c.C_ADDR IS NOT NULL AND TRIM(c.C_ADDR) IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN c.C_INFO IS NOT NULL AND TRIM(c.C_INFO) IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN c.C_BOSS IS NOT NULL AND TRIM(c.C_BOSS) IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN NVL(i.TAG_COUNT, 0) > 0 THEN 1 ELSE 0 END + CASE WHEN NVL(i.TEXT_COUNT, 0) > 0 THEN 1 ELSE 0 END + CASE WHEN NVL(img.LOGO_COUNT, 0) > 0 THEN 1 ELSE 0 END + CASE WHEN NVL(img.PROFILE_IMG_COUNT, 0) > 0 THEN 1 ELSE 0 END + CASE WHEN NVL(e.EXAMPLE_COUNT, 0) > 0 THEN 1 ELSE 0 END + CASE WHEN NVL(img.EXAMPLE_IMG_COUNT, 0) > 0 THEN 1 ELSE 0 END + CASE WHEN NVL(img.MODEL_COUNT, 0) > 0 THEN 1 ELSE 0 END ) / 11 * 100, 2) AS "profileCompleteRate" FROM COMPANY_BASE c LEFT JOIN INTERIOR_BASE i ON c.C_ID = i.C_ID AND c.C_KIND = i.C_KIND AND c.C_NAME = i.C_NAME LEFT JOIN IMG_BASE img ON c.C_ID = img.C_ID AND c.C_KIND = img.C_KIND AND c.C_NAME = img.C_NAME LEFT JOIN EXAMPLE_BASE e ON c.C_ID = e.C_ID AND c.C_KIND = e.C_KIND AND c.C_NAME = e.C_NAME

WITH BOOKING_BASE AS ( SELECT b.* FROM BOOKING b
), INVOICE_BASE AS ( SELECT DISTINCT i.ID, i.C_ID, i.C_KIND, i.C_NAME, i.B_CREATEDDATE FROM INVOICE i
), SCHEDULE_BASE AS ( SELECT s.ID, s.C_ID, s.C_KIND, s.C_NAME, s.B_CREATEDDATE, MIN(s.IS_STARTDATE) AS IS_STARTDATE, MAX(s.IS_ENDDATE) AS IS_ENDDATE FROM I_SCHEDULE s
GROUP BY s.ID, s.C_ID, s.C_KIND, s.C_NAME, s.B_CREATEDDATE ), REVIEW_BASE AS ( SELECT DISTINCT r.ID, r.C_ID, r.C_KIND, r.C_NAME, r.B_CREATEDDATE FROM I_REVIEW r WHERE r.C_KIND = 'interior'
AND r.C_ID = #{c_id}
AND r.C_NAME = #{c_name}
) SELECT COUNT(CASE WHEN b.B_STATUS = 'pending' AND b.B_CREATEDDATE < SYSDATE - 3 THEN 1 END) AS "oldPendingCount", COUNT(CASE WHEN b.B_STATUS = 'quoting' AND b.B_CREATEDDATE < SYSDATE - 7 THEN 1 END) AS "oldQuotingCount", COUNT(CASE WHEN b.B_STATUS IN ('confirmed', 'working') AND s.ID IS NULL THEN 1 END) AS "confirmedNoScheduleCount", COUNT(CASE WHEN s.IS_ENDDATE < SYSDATE AND b.B_STATUS NOT IN ('done', 'cancel') THEN 1 END) AS "scheduleDelaySuspectCount", COUNT(CASE WHEN b.B_STATUS IN ('pending', 'quoting') AND i.ID IS NULL THEN 1 END) AS "noInvoiceCount", COUNT(CASE WHEN b.B_STATUS = 'done' AND r.ID IS NULL THEN 1 END) AS "reviewRequestTargetCount" FROM BOOKING_BASE b LEFT JOIN INVOICE_BASE i ON b.ID = i.ID AND b.C_ID = i.C_ID AND b.C_KIND = i.C_KIND AND b.C_NAME = i.C_NAME AND b.B_CREATEDDATE = i.B_CREATEDDATE LEFT JOIN SCHEDULE_BASE s ON b.ID = s.ID AND b.C_ID = s.C_ID AND b.C_KIND = s.C_KIND AND b.C_NAME = s.C_NAME AND b.B_CREATEDDATE = s.B_CREATEDDATE LEFT JOIN REVIEW_BASE r ON b.ID = r.ID AND b.C_ID = r.C_ID AND b.C_KIND = r.C_KIND AND b.C_NAME = r.C_NAME AND b.B_CREATEDDATE = r.B_CREATEDDATE

WITH SCHEDULE_BASE AS ( SELECT s.ID, s.C_ID, s.C_KIND, s.C_NAME, s.B_CREATEDDATE, MIN(s.IS_STARTDATE) AS IS_STARTDATE, MAX(s.IS_ENDDATE) AS IS_ENDDATE FROM I_SCHEDULE s
GROUP BY s.ID, s.C_ID, s.C_KIND, s.C_NAME, s.B_CREATEDDATE ), REVIEW_BASE AS ( SELECT DISTINCT r.ID, r.C_ID, r.C_KIND, r.C_NAME, r.B_CREATEDDATE FROM I_REVIEW r WHERE r.C_KIND = 'interior'
AND r.C_ID = #{c_id}
AND r.C_NAME = #{c_name}
) SELECT * FROM ( SELECT b.ID AS "id", b.C_ID AS "cId", b.C_NAME AS "cName", b.B_CREATEDDATE AS "createdDate", b.B_DATE AS "bookingDate", b.B_STATUS AS "status", b.B_KIND AS "bookingKind", CASE WHEN b.B_STATUS = 'pending' AND b.B_CREATEDDATE < SYSDATE - 3 THEN 'oldPending' WHEN b.B_STATUS = 'quoting' AND b.B_CREATEDDATE < SYSDATE - 7 THEN 'oldQuoting' WHEN b.B_STATUS IN ('confirmed', 'working') AND s.ID IS NULL THEN 'noSchedule' WHEN s.IS_ENDDATE < SYSDATE AND b.B_STATUS NOT IN ('done', 'cancel') THEN 'scheduleDelay' WHEN b.B_STATUS = 'done' AND r.ID IS NULL THEN 'reviewRequest' ELSE 'normal' END AS "riskType" FROM BOOKING b LEFT JOIN SCHEDULE_BASE s ON b.ID = s.ID AND b.C_ID = s.C_ID AND b.C_KIND = s.C_KIND AND b.C_NAME = s.C_NAME AND b.B_CREATEDDATE = s.B_CREATEDDATE LEFT JOIN REVIEW_BASE r ON b.ID = r.ID AND b.C_ID = r.C_ID AND b.C_KIND = r.C_KIND AND b.C_NAME = r.C_NAME AND b.B_CREATEDDATE = r.B_CREATEDDATE
AND ( (b.B_STATUS = 'pending' AND b.B_CREATEDDATE < SYSDATE - 3) OR (b.B_STATUS = 'quoting' AND b.B_CREATEDDATE < SYSDATE - 7) OR (b.B_STATUS IN ('confirmed', 'working') AND s.ID IS NULL) OR (s.IS_ENDDATE < SYSDATE AND b.B_STATUS NOT IN ('done', 'cancel')) OR (b.B_STATUS = 'done' AND r.ID IS NULL) )
ORDER BY b.B_CREATEDDATE DESC ) WHERE ROWNUM <= 30
